use tokio::task::JoinHandle;

struct ContainerConfig {
    image_name: String,
    version: u32,
}

async fn pull_image(config: &ContainerConfig) -> Result<String, std::io::Error> {
    println!("Starting to pull image: {}@{}", config.image_name, config.version);
    tokio::time::sleep(std::time::Duration::from_millis(50)).await;
    Ok(format!("{}:{}", config.image_name, config.version))}

async fn validate_manifest(pulled_tag: &str) -> Result<bool, std::io::Error> {
    println!("Validating manifest for tag: {}", pulled_tag);
    tokio::time::sleep(std::time::Duration::from_millis(30)).await;
    Ok(true)
}

async fn run_setup_workflow(config: ContainerConfig) -> Result<String, std::io::Error> {
    let pulled_tag = pull_image(&config).await?;
    if validate_manifest(&pulled_tag).await? {
        println!("Setup complete for tag {}", pulled_tag);
        Ok(format!("Successfully configured container from {}", pulled_tag))
    } else {
        Err(std::io::Error::new(std::io::ErrorKind::InvalidData, "Manifest validation failed"))
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let config = ContainerConfig {
        image_name: String::from("nginx"),
        version: 1,
    };

    match run_setup_workflow(config).await {
        Ok(result) => println!("Final Result: {}", result),
        Err(e) => eprintln!("Error during container setup: {}", e),
    }

    Ok(())
}
